import { readFileSync, writeFileSync } from "node:fs";

const files = ["processGenerator.js", "markdownExport.js", "processStorage.js", "automationGenerator.js", "automationExport.js", "automationStorage.js", "app.js"];

function toBundleSource(file) {
  return readFileSync(file, "utf8")
    .replace(/^import[\s\S]*?from\s+["'][^"']+["'];\n/gm, "")
    .replace(/\bexport\s+/g, "");
}

const banner = `// Generated by scripts/build-bundle.js. Do not edit directly.\n// Source files: ${files.join(", ")}\n`;
const body = files.map((file) => `\n// ---- ${file} ----\n${toBundleSource(file)}`).join("\n");

writeFileSync("app.bundle.js", `${banner}(function () {\n"use strict";\n${body}\n})();\n`);
